import { defineComponentSlotStyle } from "@yamada-ui/react"

export const listStyle = defineComponentSlotStyle({
  base: {
    icon: {
      display: "inline-block",
      fontSize: "lg",
      me: "sm",
      verticalAlign: "middle",
    },
    item: {
      "&:has([data-list-icon])": {
        alignItems: "center",
        display: "inline-flex",
      },
    },
    root: {
      display: "flex",
      flexDirection: "column",
      gap: "sm",
    },
  },

  props: {
    styleType: {
      circle: { root: { ms: "1.4em" } },
      decimal: {
        item: { ps: "0.3em" },
        root: { ms: "1.2em" },
      },
      disc: { root: { ms: "1.4em" } },
      "lower-alpha": { item: { ps: "0.2em" }, root: { ms: "1.2em" } },
      square: { root: { ms: "1.4em" } },
    },
  },
})

export type ListStyle = typeof listStyle

import { page, render } from "#test/browser"
import { BoxIcon } from "../icon"
import { List } from "./"

describe("<List />", () => {
  test("sets `displayName` correctly", () => {
    expect(List.Root.displayName).toBe("ListRoot")
    expect(List.Item.displayName).toBe("ListItem")
    expect(List.Icon.displayName).toBe("ListIcon")
  })

  test("sets `className` correctly", async () => {
    await render(
      <List.Root data-testid="list-root">
        <List.Item>Item one</List.Item>
      </List.Root>,
    )

    const listRoot = page.getByTestId("list-root")
    const listItem = page.getByText("Item one")

    await expect.element(listRoot).toHaveClass("ui-list__root")
    await expect.element(listItem).toHaveClass("ui-list__item")
  })

  test("renders HTML tag correctly", async () => {
    await render(
      <List.Root data-testid="list-root">
        <List.Item>Item one</List.Item>
      </List.Root>,
    )

    const listRoot = page.getByTestId("list-root")
    const listItem = page.getByText("Item one")

    expect(listRoot.element().tagName).toBe("UL")
    expect(listItem.element().tagName).toBe("LI")
  })

  test("should render list with an icon", async () => {
    await render(
      <List.Root>
        <List.Item icon={<BoxIcon data-testid="box-icon" />} />
      </List.Root>,
    )

    const icon = page.getByTestId("box-icon")

    await expect.element(icon).toBeInTheDocument()
  })

  test("should render list with different style types", async () => {
    await render(
      <>
        <List.Root data-testid="disc" styleType="disc">
          <List.Item>List item</List.Item>
        </List.Root>
        <List.Root data-testid="decimal" styleType="decimal">
          <List.Item>List item</List.Item>
        </List.Root>
        <List.Root data-testid="square" styleType="square">
          <List.Item>Item</List.Item>
        </List.Root>
        <List.Root data-testid="circle" styleType="circle">
          <List.Item>Item</List.Item>
        </List.Root>
      </>,
    )

    const listDisc = page.getByTestId("disc")
    const listDecimal = page.getByTestId("decimal")
    const listSquare = page.getByTestId("square")
    const listCircle = page.getByTestId("circle")

    await expect.element(listDisc).toHaveStyle({
      listStyleType: "disc",
    })
    await expect.element(listDecimal).toHaveStyle({
      listStyleType: "decimal",
    })
    await expect.element(listSquare).toHaveStyle({
      listStyleType: "square",
    })
    await expect.element(listCircle).toHaveStyle({
      listStyleType: "circle",
    })
  })
})

"use client"

import type { ReactElement } from "react"
import type {
  CSSProps,
  HTMLProps,
  HTMLStyledProps,
  ThemeProps,
} from "@yamada-ui/react"
import type { ListStyle } from "./list.style"
import { cloneElement, isValidElement, useMemo } from "react"
import { createSlotComponent, styled } from "@yamada-ui/react"
import { listStyle } from "./list.style"

export interface ListItem extends ListItemProps {}

export interface ListRootProps
  extends HTMLStyledProps<"ul">, Omit<ThemeProps<ListStyle>, "styleType"> {
  /**
   * If provided, generate elements based on items.
   */
  items?: ListItem[]
  /**
   * The CSS `list-style-position` property.
   */
  stylePosition?: CSSProps["listStylePosition"]
  /**
   * The CSS `list-style-position` property.
   */
  styleType?: CSSProps["listStyleType"]
}

const {
  PropsContext: ListPropsContext,
  usePropsContext: useListPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<ListRootProps, ListStyle>("list", listStyle)

export { ListPropsContext, useListPropsContext }

/**
 * `List` is a component for displaying lists. By default, it renders a `ul` element.
 *
 * @see https://yamada-ui.com/docs/components/list
 */
export const ListRoot = withProvider<"ul", ListRootProps, "styleType">(
  ({
    as: asProp,
    children,
    items,
    stylePosition: listStylePosition,
    styleType: listStyleType = "none",
    ...rest
  }) => {
    const as = asProp ?? (listStyleType == "decimal" ? "ol" : undefined)
    const computedChildren = useMemo(() => {
      if (children) return children

      return items?.map((props, index) => <ListItem key={index} {...props} />)
    }, [children, items])

    return (
      <styled.ul
        as={as}
        listStylePosition={listStylePosition}
        listStyleType={listStyleType}
        role="list"
        {...rest}
      >
        {computedChildren}
      </styled.ul>
    )
  },
  "root",
  { transferProps: ["styleType"] },
)()

export interface ListItemProps extends HTMLStyledProps<"li"> {
  /**
   * The icon to use.
   */
  icon?: ReactElement<any>
}

export const ListItem = withContext<"li", ListItemProps>(
  ({ children, icon, ...rest }) => (
    <styled.li {...rest}>
      <ListItemIcon>{icon}</ListItemIcon>

      {children}
    </styled.li>
  ),
  "item",
)()

export interface ListIconProps extends HTMLStyledProps<"svg"> {}

export const ListItemIcon = withContext<"svg", ListIconProps>(
  ({ children, ...rest }) => {
    if (isValidElement<HTMLProps<"svg">>(children)) {
      return cloneElement(children, {
        ...children.props,
        ...rest,
        role: "presentation",
      })
    } else {
      return null
    }
  },
  "icon",
)({ "data-list-icon": "" })

export {
  ListItemIcon as Icon,
  ListItem as Item,
  ListPropsContext as PropsContext,
  ListRoot as Root,
  useListPropsContext as usePropsContext,
} from "./list"
export type {
  ListIconProps as IconProps,
  ListItemProps as ItemProps,
  ListRootProps as RootProps,
} from "./list"
